import React, { useEffect, useMemo, useState } from "react";
import CodeMirror from "@uiw/react-codemirror";
import { html as htmlLang } from "@codemirror/lang-html";
import { css as cssLang } from "@codemirror/lang-css";
import { javascript as jsLang } from "@codemirror/lang-javascript";
import { cpp } from "@codemirror/lang-cpp";
import "./App.css";

const defaultData = {
  projectName: "My CodeSnip Project",
  tab: "html",
  htmlCode: "<h1>Hello World</h1>\n<p>Write your code here...</p>",
  cssCode: "body { font-family: Arial; padding: 24px; }\nh1 { color: #22c55e; }",
  jsCode: "console.log('Hello CodeSnip');",
  cCode: "#include <stdio.h>\nint main(){ printf(\"Hello C\\n\"); return 0; }",
  cppCode:
    "#include <iostream>\nusing namespace std;\nint main(){ cout << \"Hello C++\" << endl; return 0; }",
  runEnabled: true,
};

function App() {
  const [tab, setTab] = useState(defaultData.tab);

  const [projectName, setProjectName] = useState(defaultData.projectName);

  const [htmlCode, setHtmlCode] = useState(defaultData.htmlCode);
  const [cssCode, setCssCode] = useState(defaultData.cssCode);
  const [jsCode, setJsCode] = useState(defaultData.jsCode);
  const [cCode, setCCode] = useState(defaultData.cCode);
  const [cppCode, setCppCode] = useState(defaultData.cppCode);

  const [projects, setProjects] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(null);

  const [runEnabled, setRunEnabled] = useState(defaultData.runEnabled);
  const [statusMsg, setStatusMsg] = useState("");

  const [appBg, setAppBg] = useState("#020617");
  const [panelBg, setPanelBg] = useState("#0b1220");
  const [editorBg, setEditorBg] = useState("#020617");
  const [editorText, setEditorText] = useState("#e2e8f0");
  const [accent, setAccent] = useState("#38bdf8");

  useEffect(() => {
    const savedProjects = JSON.parse(localStorage.getItem("codesnip_projects")) || [];
    const savedTheme = JSON.parse(localStorage.getItem("codesnip_theme")) || null;

    setProjects(savedProjects);

    if (savedTheme) {
      setAppBg(savedTheme.appBg || "#020617");
      setPanelBg(savedTheme.panelBg || "#0b1220");
      setEditorBg(savedTheme.editorBg || "#020617");
      setEditorText(savedTheme.editorText || "#e2e8f0");
      setAccent(savedTheme.accent || "#38bdf8");
    }
  }, []);

  useEffect(() => {
    localStorage.setItem("codesnip_projects", JSON.stringify(projects));
  }, [projects]);

  useEffect(() => {
    localStorage.setItem(
      "codesnip_theme",
      JSON.stringify({ appBg, panelBg, editorBg, editorText, accent })
    );
  }, [appBg, panelBg, editorBg, editorText, accent]);

  const activeCode = useMemo(() => {
    if (tab === "html") return htmlCode;
    if (tab === "css") return cssCode;
    if (tab === "js") return jsCode;
    if (tab === "c") return cCode;
    return cppCode;
  }, [tab, htmlCode, cssCode, jsCode, cCode, cppCode]);

  const setActiveCode = (value) => {
    if (tab === "html") setHtmlCode(value);
    else if (tab === "css") setCssCode(value);
    else if (tab === "js") setJsCode(value);
    else if (tab === "c") setCCode(value);
    else setCppCode(value);
  };

  const getLang = () => {
    if (tab === "html") return htmlLang();
    if (tab === "css") return cssLang();
    if (tab === "js") return jsLang();
    return cpp();
  };

  const getFileExt = () => {
    if (tab === "html") return "html";
    if (tab === "css") return "css";
    if (tab === "js") return "js";
    if (tab === "c") return "c";
    return "cpp";
  };

  const makePreview = () => {
    if (!runEnabled) return "";

    if (tab === "c" || tab === "cpp") {
      return `
        <html>
          <body style="font-family:Segoe UI,Arial,sans-serif;padding:24px;background:#ffffff;color:#0f172a;">
            <div style="max-width:720px;margin:auto;border:1px solid #cbd5e1;border-radius:16px;padding:24px;">
              <h2 style="margin-top:0;">${tab.toUpperCase()} editor added</h2>
              <p style="line-height:1.7;">
                Browser me C aur C++ code directly execute nahi hota.
                Is version me editor + syntax highlight + project save style added hai.
                Real execution ke liye backend compiler/API chahiye.
              </p>
              <pre style="background:#0f172a;color:#e2e8f0;padding:16px;border-radius:12px;overflow:auto;">${activeCode.replace(
                /</g,
                "&lt;"
              )}</pre>
            </div>
          </body>
        </html>
      `;
    }

    const safeHtml =
      tab === "html" ? htmlCode : `<div class="box">Write your code here</div>`;

    return `
      <html>
        <head>
          <style>
            ${tab === "css" ? activeCode : cssCode}
            body {
              margin: 0;
              background: #ffffff;
              color: #111827;
              font-family: Arial, sans-serif;
              padding: 20px;
            }
            .box {
              border: 2px dashed #94a3b8;
              border-radius: 16px;
              padding: 24px;
              background: #f8fafc;
            }
          </style>
        </head>
        <body>
          ${safeHtml}
          <script>
            try {
              ${tab === "js" ? jsCode : ""}
            } catch (e) {
              document.body.insertAdjacentHTML(
                "beforeend",
                "<pre style='color:red;white-space:pre-wrap;padding:12px;background:#fee2e2;border-radius:12px;'>" + e.message + "</pre>"
              );
            }
          </script>
        </body>
      </html>
    `;
  };

  const previewDoc = useMemo(makePreview, [runEnabled, tab, htmlCode, cssCode, jsCode, cCode, cppCode]);

  const newProject = () => {
    const next = {
      projectName: `Project ${projects.length + 1}`,
      tab: "html",
      htmlCode: "",
      cssCode: "",
      jsCode: "",
      cCode: "",
      cppCode: "",
    };
    const updated = [...projects, next];
    setProjects(updated);
    setCurrentIndex(updated.length - 1);

    setProjectName(next.projectName);
    setTab(next.tab);
    setHtmlCode(next.htmlCode);
    setCssCode(next.cssCode);
    setJsCode(next.jsCode);
    setCCode(next.cCode);
    setCppCode(next.cppCode);
    setRunEnabled(true);
    setStatusMsg("New project created");
    setTimeout(() => setStatusMsg(""), 1200);
  };

  const loadProject = (index) => {
    const p = projects[index];
    if (!p) return;

    setCurrentIndex(index);
    setProjectName(p.projectName ?? `Project ${index + 1}`);
    setTab(p.tab ?? "html");
    setHtmlCode(p.htmlCode ?? "");
    setCssCode(p.cssCode ?? "");
    setJsCode(p.jsCode ?? "");
    setCCode(p.cCode ?? "");
    setCppCode(p.cppCode ?? "");
    setRunEnabled(true);
    setStatusMsg(`Loaded ${p.projectName ?? `Project ${index + 1}`}`);
    setTimeout(() => setStatusMsg(""), 1200);
  };

  const saveProject = () => {
    const payload = {
      projectName,
      tab,
      htmlCode,
      cssCode,
      jsCode,
      cCode,
      cppCode,
    };

    let updated = [...projects];

    if (currentIndex === null) {
      updated.push(payload);
      setCurrentIndex(updated.length - 1);
    } else {
      updated[currentIndex] = payload;
    }

    setProjects(updated);
    setStatusMsg("Saved");
    setTimeout(() => setStatusMsg(""), 1200);
  };

  const clearCode = () => {
    setHtmlCode("");
    setCssCode("");
    setJsCode("");
    setCCode("");
    setCppCode("");
    setStatusMsg("Code cleared");
    setTimeout(() => setStatusMsg(""), 1200);
  };

  const copyCode = async () => {
    try {
      await navigator.clipboard.writeText(activeCode);
      setStatusMsg("Copied");
      setTimeout(() => setStatusMsg(""), 1000);
    } catch {
      setStatusMsg("Copy failed");
      setTimeout(() => setStatusMsg(""), 1200);
    }
  };

  const downloadCode = () => {
    const ext = getFileExt();
    const blob = new Blob([activeCode], { type: "text/plain;charset=utf-8" });
    const a = document.createElement("a");
    a.href = URL.createObjectURL(blob);
    a.download = `${projectName || "project"}.${ext}`;
    a.click();
    URL.revokeObjectURL(a.href);
  };

  const clearOutput = () => {
    setRunEnabled(false);
    setStatusMsg("Output cleared");
    setTimeout(() => setStatusMsg(""), 1000);
  };

  const themeVars = {
    "--app-bg": appBg,
    "--panel-bg": panelBg,
    "--editor-bg": editorBg,
    "--editor-fg": editorText,
    "--accent": accent,
  };

  return (
    <div className="app" style={themeVars}>
      <aside className="sidebar">
        <div className="sidebarHead">
          <h3>Projects</h3>
          <button className="newBtn" onClick={newProject}>
            + New
          </button>
        </div>

        <div className="projectList">
          {projects.length === 0 ? (
            <div className="emptyProject">No saved projects yet</div>
          ) : (
            projects.map((p, i) => (
              <button
                key={i}
                className={`projectItem ${currentIndex === i ? "active" : ""}`}
                onClick={() => loadProject(i)}
              >
                {p.projectName || `Project ${i + 1}`}
              </button>
            ))
          )}
        </div>
      </aside>

      <main className="main">
        <header className="topbar">
          <div className="brandArea">
            <div className="logo">C</div>
            <div>
              <h1>CodeSnip</h1>
              <p>Write, style, preview, and save your code in one place</p>
            </div>
          </div>

          <div className="topActions">
            <input
              className="projectNameInput"
              value={projectName}
              onChange={(e) => setProjectName(e.target.value)}
              placeholder="Project name"
            />
            <button onClick={saveProject}>Save</button>
            <button onClick={copyCode}>Copy</button>
            <button onClick={downloadCode}>Download</button>
            <button onClick={clearCode}>Clear Code</button>
          </div>
        </header>

        <section className="themeBar">
          <div className="themeGroup">
            <label>
              App BG
              <input type="color" value={appBg} onChange={(e) => setAppBg(e.target.value)} />
            </label>
            <label>
              Panel BG
              <input
                type="color"
                value={panelBg}
                onChange={(e) => setPanelBg(e.target.value)}
              />
            </label>
            <label>
              Editor BG
              <input
                type="color"
                value={editorBg}
                onChange={(e) => setEditorBg(e.target.value)}
              />
            </label>
            <label>
              Text
              <input
                type="color"
                value={editorText}
                onChange={(e) => setEditorText(e.target.value)}
              />
            </label>
            <label>
              Accent
              <input type="color" value={accent} onChange={(e) => setAccent(e.target.value)} />
            </label>
          </div>

          <div className="statusMsg">{statusMsg || "Auto saved in browser"}</div>
        </section>

        <nav className="tabs">
          <button className={tab === "html" ? "active" : ""} onClick={() => setTab("html")}>
            HTML
          </button>
          <button className={tab === "css" ? "active" : ""} onClick={() => setTab("css")}>
            CSS
          </button>
          <button className={tab === "js" ? "active" : ""} onClick={() => setTab("js")}>
            JavaScript
          </button>
          <button className={tab === "c" ? "active" : ""} onClick={() => setTab("c")}>
            C
          </button>
          <button className={tab === "cpp" ? "active" : ""} onClick={() => setTab("cpp")}>
            C++
          </button>
        </nav>

        <div className="container">
          <section className="editorPanel">
            <div className="panelHeader">
              <div>
                <span>{tab.toUpperCase()} Editor</span>
                <p>Write your code here</p>
              </div>

              <div className="miniControls">
                <button onClick={() => setRunEnabled(true)} className="goBtn">
                  Go
                </button>
                <button onClick={clearOutput} className="clearBtn">
                  Clear Output
                </button>
              </div>
            </div>

            <div className="editorShell">
              <CodeMirror
                value={activeCode}
                height="100%"
                extensions={[getLang()]}
                placeholder="Write your code here..."
                onChange={(value) => setActiveCode(value)}
              />
            </div>
          </section>

          <section className="previewPanel">
            <div className="panelHeader">
              <div>
                <span>Live Preview</span>
                <p>{tab === "c" || tab === "cpp" ? "Compiler required" : "Runs in browser"}</p>
              </div>
            </div>

            <div className="previewWrap">
              {tab === "c" || tab === "cpp" ? (
                <div className="noticeBox">
                  <h3>{tab.toUpperCase()} execution</h3>
                  <p>
                    Ye language browser me direct run nahi hoti. Yahan editor + save + styling
                    ready hai. Real compile/run ke liye backend compiler API chahiye.
                  </p>
                  <pre>{activeCode}</pre>
                </div>
              ) : runEnabled ? (
                <iframe
                  key={`${tab}-${projectName}-${runEnabled}`}
                  srcDoc={previewDoc}
                  title="preview"
                  sandbox="allow-scripts"
                />
              ) : (
                <div className="emptyOutput">
                  <div>
                    <h3>Output cleared</h3>
                    <p>Go दबाकर preview wapas chalao.</p>
                  </div>
                </div>
              )}
            </div>
          </section>
        </div>
      </main>
    </div>
  );
}

export default App;
